// src/pages/ngo/user/CreateFundPage.jsx
import { useState } from "react";
import { useToast } from "../../../context/ToastContext";
import PageHeader   from "../../../components/shared/PageHeader";
import DataTable    from "../../../components/shared/DataTable";
import Badge        from "../../../components/shared/Badge";
import { funds }    from "../../../data/mockData";

const fmt = (n) => n?.toLocaleString() ?? "–";
const myFunds = funds.filter((f) => f.ngo === "NGO001");

export default function CreateFundPage() {
  const toast = useToast();
  const [form, setForm] = useState({ name:"", target:"", desc:"", deadline:"", cat:"" });
  const upd = (k) => (e) => setForm((p) => ({ ...p, [k]: e.target.value }));

  return (
    <div>
      <PageHeader title="Create Fund" desc="Launch a new fundraising campaign on the blockchain" />
      <div className="grid-2">
        <div className="card">
          <div className="form-grid section-gap">
            <div className="form-group"><label>Fund Name</label><input value={form.name} onChange={upd("name")} placeholder="e.g. Ocean Cleanup 2025" /></div>
            <div className="form-group"><label>Target Amount (Tokens)</label><input value={form.target} onChange={upd("target")} type="number" placeholder="e.g. 10000" /></div>
            <div className="form-group">
              <label>Category</label>
              <select value={form.cat} onChange={upd("cat")}>
                <option value="">Select...</option>
                <option>Environment</option><option>Education</option><option>Healthcare</option><option>Relief</option>
              </select>
            </div>
            <div className="form-group"><label>Deadline</label><input value={form.deadline} onChange={upd("deadline")} type="date" /></div>
            <div className="form-group"><label>Description</label><textarea value={form.desc} onChange={upd("desc")} placeholder="Purpose and goals..." /></div>
            <div className="form-actions">
              <button className="btn btn-secondary">Clear</button>
              <button className="btn btn-primary" onClick={() => toast("Fund created and published on ledger", "success")}>Create Fund ⊕</button>
            </div>
          </div>
        </div>

        <div className="card">
          <div className="card-title" style={{ marginBottom:14 }}>Existing Funds</div>
          <DataTable
            columns={[
              { key:"id",     label:"ID",     mono:true },
              { key:"name",   label:"Name"              },
              { key:"raised", label:"Raised", render:(r) => <span className="text-gold">{fmt(r.raised)}</span> },
              { key:"status", label:"Status", render:(r) => <Badge type={r.status==="open"?"green":"red"}>{r.status}</Badge> },
            ]}
            data={myFunds}
          />
        </div>
      </div>
    </div>
  );
}
